function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'monthly');
const expectedFreshnessHours = 24 * 35;
const isFresh = (new Date() - new Date(now)) / 3600000 < expectedFreshnessHours;

const lookbackMonths = 120;
const sourceFileUrl = $('World Bank Extract URL').item.json.excelUrl;
const extractedRows = $input.all()
  .map((item) => Array.isArray(item.json.row) ? item.json.row : [])
  .filter((row) => row.length);

if (extractedRows.length < 4) {
  throw new Error('World Bank Pink Sheet extract returned too few rows');
}

function normalizeText(value) {
  return String(value ?? '').trim();
}

function normalizeNumber(value, decimals = 4) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'number') {
    if (!Number.isFinite(value)) return null;
    return Number(value.toFixed(decimals));
  }

  const text = normalizeText(value);
  if (!text || text === '...' || text === '…') return null;

  const numeric = Number(text.replace(/,/g, ''));
  if (Number.isNaN(numeric)) return null;
  return Number(numeric.toFixed(decimals));
}

function parsePeriod(periodRaw) {
  const match = /^(\d{4})M(\d{2})$/.exec(periodRaw);
  if (!match) return null;
  return {
    period_raw: periodRaw,
    report_month: `${match[1]}-${match[2]}`,
    report_date: `${match[1]}-${match[2]}-01`
  };
}

function buildStats(values, decimals = 4) {
  if (!values.length) return null;
  const min = Math.min(...values);
  const max = Math.max(...values);
  const avg = values.reduce((sum, value) => sum + value, 0) / values.length;
  return {
    min: Number(min.toFixed(decimals)),
    avg: Number(avg.toFixed(decimals)),
    max: Number(max.toFixed(decimals)),
    range: Number((max - min).toFixed(decimals))
  };
}

const headerRow = extractedRows[0].map(normalizeText);
const unitsRow = extractedRows[1].map(normalizeText);
const arabicaIndex = headerRow.findIndex((value) => value === 'Coffee, Arabica');
const robustaIndex = headerRow.findIndex((value) => value === 'Coffee, Robusta');

if (arabicaIndex === -1 || robustaIndex === -1) {
  throw new Error('World Bank Pink Sheet columns Coffee, Arabica / Coffee, Robusta not found');
}

const arabicaUnit = unitsRow[arabicaIndex] || null;
const robustaUnit = unitsRow[robustaIndex] || null;

const dapIndex       = headerRow.findIndex((v) => v.toLowerCase().includes('dap'));
const ureaIndex      = headerRow.findIndex((v) => v.toLowerCase().includes('urea'));
const potashIndex    = headerRow.findIndex((v) => v.toLowerCase().includes('potassium') || v.toLowerCase().includes('mop'));
const fertAvailable  = dapIndex !== -1 || ureaIndex !== -1 || potashIndex !== -1;
const dapUnit        = dapIndex    !== -1 ? (unitsRow[dapIndex]    || null) : null;
const ureaUnit       = ureaIndex   !== -1 ? (unitsRow[ureaIndex]   || null) : null;
const potashUnit     = potashIndex !== -1 ? (unitsRow[potashIndex] || null) : null;


const rows = extractedRows
  .slice(2)
  .map((row) => {
    const periodInfo = parsePeriod(normalizeText(row[0]));
    if (!periodInfo) return null;

    const arabica = normalizeNumber(row[arabicaIndex], 4);
    const robusta = normalizeNumber(row[robustaIndex], 4);
    if (arabica === null || robusta === null) return null;

    const dap    = dapIndex    !== -1 ? normalizeNumber(row[dapIndex],    4) : null;
    const urea   = ureaIndex   !== -1 ? normalizeNumber(row[ureaIndex],   4) : null;
    const potash = potashIndex !== -1 ? normalizeNumber(row[potashIndex], 4) : null;
    return {
      ...periodInfo,
      coffee_arabica_price: arabica,
      coffee_robusta_price: robusta,
      arabica_robusta_spread: Number((arabica - robusta).toFixed(4)),
      dap_usd_t:    dap,
      urea_usd_t:   urea,
      potash_usd_t: potash,
    };
  })
  .filter((row) => row !== null)
  .sort((a, b) => a.period_raw.localeCompare(b.period_raw));

if (!rows.length) {
  throw new Error('World Bank Pink Sheet returned no valid coffee observations');
}

const latest = rows[rows.length - 1];
const previous = rows.length > 1 ? rows[rows.length - 2] : null;
const recentSeries = rows.slice(-lookbackMonths);

const fertilizerSeries = rows.map((r) => ({
  report_date:  r.report_date,
  report_month: r.report_month,
  dap_usd_t:    r.dap_usd_t,
  urea_usd_t:   r.urea_usd_t,
  potash_usd_t: r.potash_usd_t,
})).filter((r) => r.dap_usd_t !== null || r.urea_usd_t !== null || r.potash_usd_t !== null);

const fertilizerLatest = fertilizerSeries.length ? fertilizerSeries[fertilizerSeries.length - 1] : null;
const fertilizerPrevious = fertilizerSeries.length > 1 ? fertilizerSeries[fertilizerSeries.length - 2] : null;
const fertStats = {
  dap:    buildStats(fertilizerSeries.map((r) => r.dap_usd_t).filter((v) => v !== null)),
  urea:   buildStats(fertilizerSeries.map((r) => r.urea_usd_t).filter((v) => v !== null)),
  potash: buildStats(fertilizerSeries.map((r) => r.potash_usd_t).filter((v) => v !== null)),
};

const arabicaStats = buildStats(recentSeries.map((row) => row.coffee_arabica_price));
const robustaStats = buildStats(recentSeries.map((row) => row.coffee_robusta_price));
const spreadStats = buildStats(recentSeries.map((row) => row.arabica_robusta_spread));

const changeMomArabica = previous ? Number((latest.coffee_arabica_price - previous.coffee_arabica_price).toFixed(4)) : null;
const changePctMomArabica = previous && previous.coffee_arabica_price ? Number((((latest.coffee_arabica_price - previous.coffee_arabica_price) / previous.coffee_arabica_price) * 100).toFixed(4)) : null;
const changeMomRobusta = previous ? Number((latest.coffee_robusta_price - previous.coffee_robusta_price).toFixed(4)) : null;
const changePctMomRobusta = previous && previous.coffee_robusta_price ? Number((((latest.coffee_robusta_price - previous.coffee_robusta_price) / previous.coffee_robusta_price) * 100).toFixed(4)) : null;
const changeMomSpread = previous ? Number((latest.arabica_robusta_spread - previous.arabica_robusta_spread).toFixed(4)) : null;

let movementLabel = 'mixed';
if (changeMomArabica === 0 && changeMomRobusta === 0) movementLabel = 'stable';
else if ((changeMomArabica ?? 0) > 0 && (changeMomRobusta ?? 0) > 0) movementLabel = 'coffee_benchmarks_up';
else if ((changeMomArabica ?? 0) < 0 && (changeMomRobusta ?? 0) < 0) movementLabel = 'coffee_benchmarks_down';

let summaryEn = `Latest World Bank Pink Sheet monthly observation for ${latest.report_month} shows Arabica at ${latest.coffee_arabica_price.toFixed(4)} USD/kg and Robusta at ${latest.coffee_robusta_price.toFixed(4)} USD/kg.`;
const signals = [
  `Latest Arabica ${latest.coffee_arabica_price.toFixed(4)} USD/kg`,
  `Latest Robusta ${latest.coffee_robusta_price.toFixed(4)} USD/kg`,
  `Latest Arabica-Robusta spread ${latest.arabica_robusta_spread.toFixed(4)} USD/kg`,
  `${lookbackMonths}-month Arabica range ${arabicaStats ? arabicaStats.range.toFixed(4) : 'n/a'} USD/kg`,
  `${lookbackMonths}-month Robusta range ${robustaStats ? robustaStats.range.toFixed(4) : 'n/a'} USD/kg`
];

if (previous) {
  summaryEn += ` Versus ${previous.report_month}, Arabica changed by ${changeMomArabica.toFixed(4)} USD/kg (${changePctMomArabica.toFixed(4)}%) and Robusta changed by ${changeMomRobusta.toFixed(4)} USD/kg (${changePctMomRobusta.toFixed(4)}%).`;

  if (movementLabel === 'coffee_benchmarks_up') {
    summaryEn += ' Both coffee benchmarks moved up month over month.';
    signals.push('Arabica and Robusta both increased month over month');
  } else if (movementLabel === 'coffee_benchmarks_down') {
    summaryEn += ' Both coffee benchmarks moved down month over month.';
    signals.push('Arabica and Robusta both decreased month over month');
  } else if (movementLabel === 'stable') {
    signals.push('Arabica and Robusta unchanged month over month');
  } else {
    summaryEn += ' Arabica and Robusta moved in different directions month over month.';
    signals.push('Arabica and Robusta moved in different directions month over month');
  }
}

return [{
  json: {
    source: 'WB_PINK_SHEET',
    source_format: 'xlsx',
    source_file_url: sourceFileUrl,
    source_url: sourceFileUrl,
    country: 'BR',
    macroarea: 'prices',
    collected_at: now,
    collected_period: _collectedPeriod,
        is_fresh: isFresh,
    dataset: 'CMO_HISTORICAL_DATA_MONTHLY',
    sheet_name: 'Monthly Prices',
    price_unit: arabicaUnit === robustaUnit ? arabicaUnit : null,
    arabica_unit: arabicaUnit,
    robusta_unit: robustaUnit,
    lookback_months: lookbackMonths,
    total_observations: rows.length,
    report_period: latest.period_raw,
    report_month: latest.report_month,
    report_date: latest.report_date,
    coffee_arabica_price: latest.coffee_arabica_price,
    coffee_robusta_price: latest.coffee_robusta_price,
    arabica_robusta_spread: latest.arabica_robusta_spread,
    movement_label: movementLabel,
    previous_report_period: previous ? previous.period_raw : null,
    previous_report_month: previous ? previous.report_month : null,
    previous_report_date: previous ? previous.report_date : null,
    previous_coffee_arabica_price: previous ? previous.coffee_arabica_price : null,
    previous_coffee_robusta_price: previous ? previous.coffee_robusta_price : null,
    previous_arabica_robusta_spread: previous ? previous.arabica_robusta_spread : null,
    change_mom_arabica: changeMomArabica,
    change_pct_mom_arabica: changePctMomArabica,
    change_mom_robusta: changeMomRobusta,
    change_pct_mom_robusta: changePctMomRobusta,
    change_mom_spread: changeMomSpread,
    coffee_price_stats_lookback: {
      arabica: arabicaStats,
      robusta: robustaStats,
      spread: spreadStats
    },
    recent_series: recentSeries,
    summary_en: summaryEn,
    signals,
    fertilizer_available: fertAvailable,
    fertilizer_units: { dap: dapUnit, urea: ureaUnit, potash: potashUnit },
    fertilizer_latest: fertilizerLatest,
    fertilizer_previous: fertilizerPrevious,
    fertilizer_stats: fertStats,
    fertilizer_series: fertilizerSeries,
    _chart_fields: ["recent_series", "fertilizer_series"]
  }
}];

const now = new Date().toISOString();
const meta = $('World Bank Parse Signals').item.json;

return [{
  json: {
    source: 'WB_PINK_SHEET',
    country: 'BR',
    macroarea: 'prices',
    cadenza: 'monthly',
    run_date: now,
    status: 'done',
    completed_at: now,
    report_period: meta.report_period || null,
  },
}];

const html = $input.first().json.data;
const match = /https:\/\/thedocs\.worldbank\.org\/en\/doc\/[^"']+CMO-Historical-Data-Monthly\.xlsx/.exec(html);
if (!match) {
  throw new Error('World Bank Pink Sheet: URL Excel non trovato nella pagina commodity-markets');
}
return [{ json: { excelUrl: match[0] } }];

const raw = ($json.text || '').trim();
const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
const parsed = JSON.parse(cleaned);
const base = $('World Bank Pink Sheet Parse').item.json;

return [{ json: {
  ...base,
  rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
  rule_based_movement_label: base.movement_label || 'mixed',
  fallback_summary_en: base.summary_en || '',
  movement_label: parsed.movement_label || base.movement_label || 'mixed',
  signals: Array.isArray(parsed.signals) && parsed.signals.length ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
  summary_en: parsed.summary_en || base.summary_en || ''
}}];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '07_WORLD_BANK_PINK_SHEET',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json, binary: item.binary }];
